export type CountryIso = "IN" | "US" | "GB" | "AE" | "SG";

export interface CountryOption {
  iso: CountryIso;
  label: string;
  dialCode: string;
  nationalLength?: number;
}

export const COUNTRY_OPTIONS: CountryOption[] = [
  { iso: "IN", label: "India (+91)", dialCode: "91", nationalLength: 10 },
  { iso: "US", label: "United States (+1)", dialCode: "1", nationalLength: 10 },
  { iso: "GB", label: "United Kingdom (+44)", dialCode: "44", nationalLength: 10 },
  { iso: "AE", label: "UAE (+971)", dialCode: "971", nationalLength: 9 },
  { iso: "SG", label: "Singapore (+65)", dialCode: "65", nationalLength: 8 },
];

const COUNTRY_MAP = Object.fromEntries(
  COUNTRY_OPTIONS.map((option) => [option.iso, option])
) as Record<CountryIso, CountryOption>;

const DIGITS_ONLY = /[^0-9]/g;
const E164_MIN = 8;
const E164_MAX = 15;

export function normalizeCountryIso(raw?: string | null): CountryIso {
  const candidate = (raw || "").toUpperCase();
  if (candidate in COUNTRY_MAP) {
    return candidate as CountryIso;
  }
  return "IN";
}

export function normalizePhoneNumber(rawPhone: string, countryIso: string | null | undefined): { ok: true; digits: string; e164: string; countryIso: CountryIso } | { ok: false; error: string } {
  const selectedCountry = COUNTRY_MAP[normalizeCountryIso(countryIso)];
  const input = (rawPhone || "").trim();
  if (!input) {
    return { ok: false, error: "Phone number is required." };
  }

  const hasPlus = input.startsWith("+");
  let digits = input.replace(DIGITS_ONLY, "");

  if (!digits) {
    return { ok: false, error: "Phone number contains no digits." };
  }

  // Convert international dialing prefix 00XXXXXXXX to +XXXXXXXX semantics.
  if (!hasPlus && digits.startsWith("00")) {
    digits = digits.slice(2);
  }

  if (!hasPlus) {
    // If a likely national number is entered, prefix with selected country.
    if (selectedCountry.nationalLength && digits.length === selectedCountry.nationalLength) {
      digits = `${selectedCountry.dialCode}${digits}`;
    }
  }

  if (digits.length < E164_MIN || digits.length > E164_MAX) {
    return {
      ok: false,
      error: `Invalid phone number length after normalization. Expected ${E164_MIN}-${E164_MAX} digits, got ${digits.length}.`,
    };
  }

  return {
    ok: true,
    digits,
    e164: `+${digits}`,
    countryIso: selectedCountry.iso,
  };
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import getDb from "@/lib/db";

// GET a single profile
export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await params;
  const db = getDb();
  const profile = db
    .prepare("SELECT * FROM profiles WHERE id = ? AND user_id = ?")
    .get(id, session.user.id) as Record<string, unknown> | undefined;

  if (!profile) {
    return NextResponse.json({ error: "Profile not found" }, { status: 404 });
  }

  return NextResponse.json({
    ...profile,
    medical_conditions: JSON.parse((profile.medical_conditions as string) || "[]"),
    allergies: JSON.parse((profile.allergies as string) || "[]"),
    medications: JSON.parse((profile.medications as string) || "[]"),
    goals: JSON.parse((profile.goals as string) || "[]"),
  });
}

// PUT update a profile
export async function PUT(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await params;

  try {
    const body = await req.json();
    const db = getDb();

    // Verify ownership
    const existing = db
      .prepare("SELECT id FROM profiles WHERE id = ? AND user_id = ?")
      .get(id, session.user.id);
    if (!existing) {
      return NextResponse.json({ error: "Profile not found" }, { status: 404 });
    }

    db.prepare(`
      UPDATE profiles SET
        name = ?, relationship = ?, age = ?, gender = ?, height_cm = ?, weight_kg = ?,
        activity_level = ?, dietary_preference = ?, medical_conditions = ?, allergies = ?,
        medications = ?, goals = ?, additional_notes = ?, updated_at = CURRENT_TIMESTAMP
      WHERE id = ? AND user_id = ?
    `).run(
      body.name,
      body.relationship || "other",
      body.age || null,
      body.gender || null,
      body.height_cm || null,
      body.weight_kg || null,
      body.activity_level || "moderate",
      body.dietary_preference || "no_preference",
      JSON.stringify(body.medical_conditions || []),
      JSON.stringify(body.allergies || []),
      JSON.stringify(body.medications || []),
      JSON.stringify(body.goals || []),
      body.additional_notes || "",
      id,
      session.user.id
    );

    return NextResponse.json({ message: "Profile updated" });
  } catch (error) {
    console.error("Update profile error:", error);
    return NextResponse.json({ error: "Failed to update profile" }, { status: 500 });
  }
}

// DELETE a profile
export async function DELETE(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await auth();
  if (!session?.user?.id) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await params;
  const db = getDb();

  const result = db
    .prepare("DELETE FROM profiles WHERE id = ? AND user_id = ?")
    .run(id, session.user.id);

  if (result.changes === 0) {
    return NextResponse.json({ error: "Profile not found" }, { status: 404 });
  }

  return NextResponse.json({ message: "Profile deleted" });
}

import getDb from "@/lib/db";

interface AiConfig {
  apiUrl: string;
  apiKey: string;
  model: string;
}

export function getAiConfig(userId?: string): AiConfig {
  const defaults: AiConfig = {
    apiUrl: process.env.LITELLM_API_URL || "http://localhost:4000",
    apiKey: process.env.LITELLM_API_KEY || "",
    model: process.env.DEFAULT_MODEL || "gpt-4o",
  };

  if (userId) {
    try {
      const db = getDb();
      const settings = db
        .prepare("SELECT * FROM user_settings WHERE user_id = ?")
        .get(userId) as
        | { api_url: string; api_key: string; preferred_model: string }
        | undefined;

      if (settings) {
        if (settings.api_url) defaults.apiUrl = settings.api_url;
        if (settings.api_key) defaults.apiKey = settings.api_key;
        if (settings.preferred_model) defaults.model = settings.preferred_model;
      }
    } catch {
      // Use defaults on error
    }
  }

  return defaults;
}

export interface ProfileData {
