  try {
    const body = await req.json();
    const db = getDb();
    const id = uuidv4();
    const settings = db
      .prepare("SELECT default_country_iso FROM user_settings WHERE user_id = ?")
      .get(session.user.id) as { default_country_iso?: string | null } | undefined;
