        content,
        plan_type: type,
        focus_areas: areas,
        model_used: config.model,
        created_at: new Date().toISOString(),
        isTemp: true,
      });
    }

    // Legacy behavior: save and generate
    const planId = uuidv4();
    db.prepare(`
